366: namespace mozilla {
367: class ThreadSafeAutoRefCnt {
368:  public:
369:   constexpr ThreadSafeAutoRefCnt() : mValue(0) {}
370:   constexpr explicit ThreadSafeAutoRefCnt(nsrefcnt aValue) : mValue(aValue) {}
371: 
372:   ThreadSafeAutoRefCnt(const ThreadSafeAutoRefCnt&) = delete;
373:   void operator=(const ThreadSafeAutoRefCnt&) = delete;
374: 
375:   // only support prefix increment/decrement
376:   MOZ_ALWAYS_INLINE nsrefcnt operator++() {
377:     // Memory synchronization is not required when incrementing a
378:     // reference count.  The first increment of a reference count on a
379:     // thread is not important, since the first use of the object on a
380:     // thread can happen before it.  What is important is the transfer
381:     // of the pointer to that thread, which may happen prior to the
382:     // first increment on that thread.  The necessary memory
383:     // synchronization is done by the mechanism that transfers the
384:     // pointer between threads.
385:     return mValue.fetch_add(1, std::memory_order_relaxed) + 1;
386:   }
387:   MOZ_ALWAYS_INLINE nsrefcnt operator--() {
388:     // Since this may be the last release on this thread, we need
389:     // release semantics so that prior writes on this thread are visible
390:     // to the thread that destroys the object when it reads mValue with
391:     // acquire semantics.
392:     nsrefcnt result = mValue.fetch_sub(1, std::memory_order_release) - 1;
393:     if (result == 0) {
394:       // We're going to destroy the object on this thread, so we need
395:       // acquire semantics to synchronize with the memory released by
396:       // the last release on other threads, that is, to ensure that
397:       // writes prior to that release are now visible on this thread.
398: #ifdef MOZ_TSAN
399:       // TSan doesn't understand std::atomic_thread_fence, so in order
400:       // to avoid a false positive for every time a refcounted object
401:       // is deleted, we replace the fence with an atomic operation.
402:       mValue.load(std::memory_order_acquire);
403: #else
404:       std::atomic_thread_fence(std::memory_order_acquire);
405: #endif
406:     }
407:     return result;
408:   }
409: 
410:   MOZ_ALWAYS_INLINE nsrefcnt operator=(nsrefcnt aValue) {
411:     // Use release semantics since we're not sure what the caller is
412:     // doing.
413:     mValue.store(aValue, std::memory_order_release);
414:     return aValue;
415:   }
416:   MOZ_ALWAYS_INLINE operator nsrefcnt() const { return get(); }
417:   MOZ_ALWAYS_INLINE nsrefcnt get() const {
418:     // Use acquire semantics since we're not sure what the caller is
419:     // doing.
420:     return mValue.load(std::memory_order_acquire);
421:   }
422: 
423:   static const bool isThreadSafe = true;
424: 
425:  private:
426:   nsrefcnt operator++(int) = delete;
427:   nsrefcnt operator--(int) = delete;
428:   std::atomic<nsrefcnt> mValue;
429: };
